const { Pool } = require\('pg'\);
const crypto = require\('crypto'\);
const fs = require\('fs'\);
const path = require\('path'\);

const pool = new Pool\({ connectionString: 'postgresql://postgres:CmiqeQOOcgeRCsMfEVwobGDRSNDoKqoS@monorail.proxy.rlwy.net:48896/railway', ssl: { rejectUnauthorized: false } }\);

const MIGRATIONS_DIR = path.join\(__dirname, 'lib/db/migrations'\);
const journal = JSON.parse\(fs.readFileSync\(path.join\(MIGRATIONS_DIR, 'meta/_journal.json'\), 'utf8'\)\);

async function run\(\) {
  const { rows: existing } = await pool.query\('SELECT created_at FROM drizzle.__drizzle_migrations ORDER BY created_at'\);
  const existingTimestamps = new Set\(existing.map\(r => String\(r.created_at\)\)\);

  for \(const entry of journal.entries\) {
    if \(existingTimestamps.has\(String\(entry.when\)\)\) {
      console.log\('Already applied:', entry.tag\);
      continue;
    }
    const sql = fs.readFileSync\(path.join\(MIGRATIONS_DIR, entry.tag + '.sql'\), 'utf8'\);
    const hash = crypto.createHash\('sha256'\).update\(sql\).digest\('hex'\);
    await pool.query\('INSERT INTO drizzle.__drizzle_migrations \(hash, created_at\) VALUES \(\\$1, \\$2\)', [hash, entry.when]\);
    console.log\('Inserted:', entry.tag, 'when:', entry.when\);
  }
  await pool.end\(\);
}

run\(\).catch\(e => { console.error\(e.message\); pool.end\(\); }\);
" 2>&1)
